// toggleServerAddPanel discloses the "Add server" type chooser, keeping the
// trigger's aria-expanded in sync (mirrors the toggleConnectionForm pattern).
func toggleServerAddPanel() templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_toggleServerAddPanel_ba36`,
		Function: `function __templ_toggleServerAddPanel_ba36(){var panel = document.getElementById("server-add-panel");
	if (panel) {
		panel.classList.toggle("hidden");
		var btn = document.querySelector('[aria-controls="server-add-panel"]');
		if (btn) {
			btn.setAttribute('aria-expanded', String(!panel.classList.contains('hidden')));
		}
	}
}`,
		Call:       templ.SafeScript(`__templ_toggleServerAddPanel_ba36`),
		CallInline: templ.SafeScriptInline(`__templ_toggleServerAddPanel_ba36`),
	}
}

